
import React from "react";
import { useEffect, useState } from "react";
import { apiFetch } from "@/lib/api";
import { isSuperAdmin } from "@/lib/auth";

import CustomersTable from "./CustomersTable";
import CustomerModal from "./CustomerModal";

export type Customer = {
  id: string;
  full_name_ar: string;
  full_name_en?: string;
  mobile_number: string;
  national_id?: string;
  city?: string;
  address?: string;
  risk_level?: string;
  status?: string;
};

export type CustomerForm = {
  full_name_ar: string;
  full_name_en: string;
  mobile_number: string;
  national_id: string;
  city: string;
  address: string;
};

const emptyForm: CustomerForm = {
  full_name_ar: "",
  full_name_en: "",
  mobile_number: "",
  national_id: "",
  city: "",
  address: "",
};

export default function CustomersClient() {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [editingCustomer, setEditingCustomer] =
    useState<Customer | null>(null);

  const [isModalOpen, setIsModalOpen] = useState(false);

  const [superAdmin, setSuperAdmin] = useState(false);

  const [form, setForm] = useState<CustomerForm>(emptyForm);

  useEffect(() => {
    loadCustomers();
    setSuperAdmin(isSuperAdmin());
  }, []);

  async function loadCustomers() {
    try {
      setLoading(true);
      setError("");

      const data = await apiFetch("/merchant/customers");
      setCustomers(data);
    } catch (err: any) {
      setError(err.message || "Failed to load customers");
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingCustomer(null);
    setForm(emptyForm);
    setIsModalOpen(true);
  }

  function openEditModal(customer: Customer) {
    setEditingCustomer(customer);

    setForm({
      full_name_ar: customer.full_name_ar || "",
      full_name_en: customer.full_name_en || "",
      mobile_number: customer.mobile_number || "",
      national_id: customer.national_id || "",
      city: customer.city || "",
      address: customer.address || "",
    });

    setIsModalOpen(true);
  }

  async function saveCustomer(e: React.FormEvent) {
    e.preventDefault();

    try {
      if (editingCustomer) {
        await apiFetch(`/merchant/customers/${editingCustomer.id}`, {
          method: "PATCH",
          body: JSON.stringify(form),
        });
      } else {
        await apiFetch("/merchant/customers", {
          method: "POST",
          body: JSON.stringify(form),
        });
      }

      setIsModalOpen(false);
      setEditingCustomer(null);
      setForm(emptyForm);

      loadCustomers();
    } catch (err: any) {
      setError(err.message);
    }
  }

  async function deactivateCustomer(id: string) {
    if (!confirm("Deactivate this customer?")) return;

    try {
      await apiFetch(`/merchant/customers/${id}`, {
        method: "DELETE",
      });

      loadCustomers();
    } catch (err: any) {
      setError(err.message);
    }
  }

  return (
    <>
      {/* Toolbar */}

      <div className="mb-6 flex items-center justify-between">
        <button
          onClick={openAddModal}
          className="rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
        >
          Add Customer
        </button>
      </div>

      {/* Error */}

      {error && (
        <div className="mb-6 rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700 dark:border-error-500/30 dark:bg-error-500/10 dark:text-error-400">
          {error}
        </div>
      )}

      {/* Table */}

      <CustomersTable
        customers={customers}
        loading={loading}
        onEdit={openEditModal}
        onDeactivate={deactivateCustomer}
      />

      {/* Modal */}

      <CustomerModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        editingCustomer={editingCustomer}
        form={form}
        setForm={setForm}
        onSubmit={saveCustomer}
        superAdmin={superAdmin}
      />
    </>
  );
}